const hubspot = $('Scan HubSpot').first().json;
const houzz = $('Scan Houzz').first()?.json || { result: { detection_status: 'SKIPPED' } };

const hbStatus = hubspot?.result?.detection_status || 'UNKNOWN';
const hzStatus = houzz?.result?.detection_status || 'UNKNOWN';

const needsAction = [hbStatus, hzStatus].some(s => ['ERROR', 'STALE', 'CHANGES_DETECTED'].includes(s));
const isError = [hbStatus, hzStatus].some(s => ['ERROR', 'STALE'].includes(s));

const lines = [];
if (hbStatus === 'CHANGES_DETECTED') {
  const n = hubspot?.result?.summary?.total_new_records_24h || 0;
  lines.push(`HubSpot: ${n} new record(s) — syncing`);
} else if (hbStatus === 'ERROR' || hbStatus === 'STALE') {
  lines.push(`HubSpot: ⚠️ ${hbStatus}`);
} else {
  lines.push('HubSpot: no new data');
}

if (hzStatus === 'CHANGES_DETECTED') {
  const n = houzz?.result?.summary?.total_new_records_24h || 0;
  lines.push(`Houzz: ${n} new record(s) — syncing`);
} else if (hzStatus === 'NO_DATA') {
  lines.push('Houzz: awaiting Browser extraction');
} else if (hzStatus === 'ERROR' || hzStatus === 'STALE') {
  lines.push(`Houzz: ⚠️ ${hzStatus}`);
} else {
  lines.push('Houzz: no new data');
}

return [{
  json: {
    needs_notify: needsAction,
    is_error: isError,
    title: isError ? '⚠️ Discovery Engine Alert' : (needsAction ? '🔄 New Data Detected' : null),
    message: lines.join(' | '),
    priority: isError ? 'high' : 'default',
    hubspot_status: hbStatus,
    houzz_status: hzStatus,
  }
}];
